// Background.js: Get streamId and pass to offscreen
// CRITICAL: Only call this AFTER user explicitly clicks a button in the UI
// This ensures the extension has been invoked on the page (activeTab requirement)
async function startCapture(tabId) {
  try {
    // Notify UI that capture is starting
    chrome.runtime.sendMessage({ type: 'capture-status', status: 'checking', message: 'Checking if tab can be captured...' });

    // Get tab info to check URL - CRITICAL: Do this FIRST before any capture attempt
    let tab;
    try {
      tab = await chrome.tabs.get(tabId);
    } catch (error) {
      const userMessage = 'Cannot access tab information. Please ensure the tab is active and try again.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // CRITICAL: Validate tab URL BEFORE attempting any capture
    // DO NOT call getMediaStreamId if URL validation fails
    if (!tab.url) {
      const userMessage = 'Tab URL is not available. Please navigate to a regular website (http:// or https://) and try again.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    const url = tab.url.toLowerCase().trim();

    // CRITICAL: Check for Chrome internal pages FIRST - these cannot be captured
    const blockedProtocols = ['chrome://', 'chrome-extension://', 'edge://', 'about:', 'moz-extension://', 'opera://', 'brave://'];
    const isBlocked = blockedProtocols.some(protocol => url.startsWith(protocol));

    if (isBlocked) {
      const userMessage = 'Cannot capture Chrome internal pages (chrome://newtab, chrome://settings, etc.). Please navigate to a regular website (http:// or https://) like google.com, then click the extension icon on that page, and try again.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // CRITICAL: Only allow http:// and https:// URLs - reject everything else
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      const userMessage = 'Cannot capture this page type. Please navigate to a regular website (http:// or https://) and ensure you clicked the extension icon first.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // Additional check: if URL is about:blank or empty string
    if (url === 'about:blank' || url.length === 0) {
      const userMessage = 'Cannot capture blank pages. Please navigate to a regular website and ensure you clicked the extension icon first.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // Final validation: ensure URL looks like a valid web page
    try {
      new URL(tab.url); // Will throw if invalid
    } catch (urlError) {
      const userMessage = 'Invalid page URL. Please navigate to a regular website (http:// or https://) and try again.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // CRITICAL: Final safety check - double-check URL one more time before calling getMediaStreamId
    // This prevents any edge cases where chrome:// pages might slip through
    if (url.includes('chrome://') || url.includes('chrome-extension://') || url.includes('about:')) {
      const userMessage = 'Cannot capture Chrome internal pages. Please navigate to a regular website (http:// or https://) like google.com, then click the extension icon on that page, and try again.';
      chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
      throw new Error(userMessage);
    }

    // CRITICAL: At this point, URL validation has passed (http:// or https://)
    // Now we can attempt capture, but it may still fail if extension wasn't invoked
    // Notify UI that we're requesting access
    chrome.runtime.sendMessage({ type: 'capture-status', status: 'requesting', message: 'Requesting access to tab audio...' });

    // CRITICAL: Wrap getMediaStreamId in try-catch because it will throw if:
    // 1. Extension wasn't invoked on this page (even if URL is valid)
    // 2. Any other capture error occurs
    let streamId;
    try {
      const capturePromise = chrome.tabCapture.getMediaStreamId({ targetTabId: tabId });
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Capture request timed out after 5 seconds.')), 5000)
      );

      streamId = await Promise.race([capturePromise, timeoutPromise]);
    } catch (captureError) {
      const errorMessage = captureError.message || String(captureError);

      if (errorMessage.includes('Extension has not been invoked') || errorMessage.includes('activeTab permission') || errorMessage.includes('Chrome pages cannot be captured')) {
        const userMessage = 'Cannot capture this page. Please ensure: (1) You are on a regular website (not chrome://newtab or chrome:// pages) - navigate to google.com or any http:///https:// site, (2) You clicked the extension icon on that page to open the popup/sidepanel (this grants activeTab permission), (3) Then try capturing again.';
        chrome.runtime.sendMessage({ type: 'capture-error', error: userMessage });
        throw new Error(userMessage);
      }

      // Re-throw other errors to be handled by outer catch
      throw captureError;
    }

    // Check if offscreen document already exists
    const existingDocs = await chrome.offscreen.hasDocument();
    if (!existingDocs) {
      await chrome.offscreen.createDocument({ url: 'offscreen.html', reasons: ['USER_MEDIA'], justification: 'Recording' });
    }

    // Send streamId to offscreen document
    chrome.runtime.sendMessage({ type: 'start-recording', target: 'offscreen', streamId });
    chrome.runtime.sendMessage({ type: 'capture-status', status: 'success', message: 'Recording started' });
  } catch (error) {
    console.error('Failed to start capture:', error);
    const errorMessage = error.message || String(error);
    let userFriendlyMessage = errorMessage;

    // Handle specific error patterns - this is the final catch for any remaining errors
    if (errorMessage.includes('Extension has not been invoked') || errorMessage.includes('activeTab permission') || errorMessage.includes('Chrome pages cannot be captured')) {
      userFriendlyMessage = 'Cannot capture this page. Please ensure: (1) You are on a regular website (not chrome://newtab or chrome:// pages), (2) You clicked the extension icon on that page to open the popup/sidepanel, (3) Then try capturing again.';
    } else if (errorMessage.includes('chrome://')) {
      userFriendlyMessage = 'Cannot capture Chrome internal pages. Please navigate to a regular website (http:// or https://) and try again.';
    } else if (errorMessage.includes('timed out')) {
      userFriendlyMessage = 'Capture request timed out. Please ensure the extension icon was clicked on this page and you are on a regular website (not chrome:// pages).';
    }

    chrome.runtime.sendMessage({ type: 'capture-error', error: userFriendlyMessage });
  }
}

// Listen for capture requests from UI (user must click a button)
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type === 'start-capture') {
    // Get current active tab
    chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
      if (tabs[0]) {
        startCapture(tabs[0].id);
      } else {
        chrome.runtime.sendMessage({ type: 'capture-error', error: 'No active tab found. Please open a website and try again.' });
      }
    });
    sendResponse({ success: true });
  }
  return true; // Keep message channel open for async response
});

// Offscreen.js: Handle stream and MediaRecorder
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type === 'start-recording' && message.target === 'offscreen') {
    const streamId = message.streamId;

    navigator.mediaDevices.getUserMedia({
      audio: { mandatory: { chromeMediaSource: 'tab', chromeMediaSourceId: streamId } }
    }).then(stream => {
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      const chunks = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) chunks.push(event.data); 
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = () => {
          chrome.runtime.sendMessage({ type: 'recording-complete', data: reader.result });
        };
        reader.readAsDataURL(blob);
      };

      mediaRecorder.start();

      // Listen for stop message
      chrome.runtime.onMessage.addListener((msg) => {
        if (msg.type === 'stop-recording') {
          mediaRecorder.stop();
          stream.getTracks().forEach(track => track.stop());
        }
      });
    }).catch(error => {
      console.error('Failed to get media stream:', error);
      chrome.runtime.sendMessage({ type: 'capture-error', error: 'Failed to access media stream. Please ensure the tab is active and try again.' });
    });

    sendResponse({ success: true });
    return true; // Keep message channel open
  }
});

