const startButton = document.getElementById('start-recording');
if (startButton) {
  startButton.addEventListener('click', () => {
    chrome.runtime.sendMessage({ type: 'start-capture' }, (response) => {
      if (chrome.runtime.lastError) {
        console.error('Error sending message:', chrome.runtime.lastError);
        const errorElement = document.getElementById('error-message');
        if (errorElement) {
          errorElement.textContent = 'Failed to start capture. Please try again.';
          errorElement.style.display = 'block';
        }
      }
    });
  });
}

// Listen for status updates
chrome.runtime.onMessage.addListener((message) => {
  if (message.type === 'capture-status') {
    const statusElement = document.getElementById('capture-status');
    if (statusElement) {
      statusElement.textContent = message.message;
      statusElement.style.display = 'block';
    }
  } else if (message.type === 'capture-error') {
    const errorElement = document.getElementById('error-message');
    if (errorElement) {
      errorElement.textContent = message.error;
      errorElement.style.display = 'block';
    }
    // Also hide status if error occurs
    const statusElement = document.getElementById('capture-status');
    if (statusElement) {
      statusElement.style.display = 'none';
    }
  }
});
